import React, { useState } from 'react';
import './login-page.css'; // Custom CSS for styling the login page
import Header from '../../components/Header/Header.tsx';
import Footer from '../../components/Footer/Footer.tsx';

const LoginPage: React.FC = () => {
  const [email, setEmail] = useState<string>(''); // State for email input
  const [password, setPassword] = useState<string>(''); // State for password input
  const [userType, setUserType] = useState<string>('admin'); // State for user type selection
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false); // State to manage form submission

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault(); // Prevent default form submission
    if (isSubmitting) return; // Prevent multiple submissions

    // Basic validation
    if (!email.trim() || !password.trim()) {
      alert('Please fill in all fields.');
      return;
    }

    setIsSubmitting(true); // Set submitting state
    try {
      // Simulate login API call
      const response = await fakeLoginApi(email, password, userType);
      console.log('Login successful:', response);
      alert(`Welcome ${userType}!`);
      // Redirect based on user type (e.g., use React Router to navigate)
    } catch (error) {
      console.error('Login failed:', error);
      alert('Invalid credentials. Please try again.');
    } finally {
      setIsSubmitting(false); // Reset submitting state
    }
  };

  // Mock API function for demonstration
  const fakeLoginApi = (email: string, password: string, userType: string) =>
    new Promise((resolve, reject) => {
      setTimeout(() => {
        if (email === 'test@example.com' && password === 'password123') {
          resolve({ email, userType });
        } else {
          reject('Invalid credentials');
        }
      }, 1000);
    });

  return (
    <div className="login-page">
      <Header />
      <div className="login-container">
        <h2>Login</h2>
        <form onSubmit={handleLogin} className="login-form">
          <div className="form-group">
            <label htmlFor="email">Email</label>
            <input
              type="email"
              id="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Enter your email"
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="password">Password</label>
            <input
              type="password"
              id="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter your password"
              required
            />
          </div>
         
          <button type="submit" disabled={isSubmitting} className="login-button">
            {isSubmitting ? 'Logging in...' : 'Login'}
          </button>
        </form>
      </div>
      <Footer />
    </div>
  );
};

export default LoginPage;
